import { useState, useEffect, useRef } from "react";

const IMGS = {"panorama": "data:image/jpeg;base64,", "sunrise": "data:image/jpeg;base64,", "rocks": "data:image/jpeg;base64,", "pavilion": "data:image/jpeg;base64,", "garden": "data:image/jpeg;base64,", "oyster": "data:image/jpeg;base64,", "workspace": "data:image/jpeg;base64,", "ocean": "data:image/jpeg;base64,"};

function useInView(threshold = 0.12) {
  const ref = useRef(null);
  const [inView, setInView] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) { setInView(true); obs.unobserve(el); } },
      { threshold }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, [threshold]);
  return [ref, inView];
}

function Reveal({ children, delay = 0, style = {} }) {
  const [ref, inView] = useInView();
  return (
    <div ref={ref} style={{
      ...style,
      opacity: inView ? 1 : 0,
      transform: inView ? "translateY(0)" : "translateY(36px)",
      transition: `opacity 1s cubic-bezier(0.16,1,0.3,1) ${delay}s, transform 1s cubic-bezier(0.16,1,0.3,1) ${delay}s`,
    }}>
      {children}
    </div>
  );
}

/* ─── NAV ─── */
