/* ─── MAIN APP ─── */
export default function WandoWorkation() {
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => {
    const h = () => setScrolled(window.scrollY > 60);
    window.addEventListener("scroll", h);
    return () => window.removeEventListener("scroll", h);
  }, []);

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:wght@300;400;500&family=Noto+Sans+KR:wght@200;300;400;500&family=Noto+Serif+KR:wght@200;300;400;500&display=swap');
        :root {
          --serif: 'Noto Serif KR', 'Cormorant Garamond', serif;
          --sans: 'Noto Sans KR', sans-serif;
        }
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { background: #ffffff; color: #222222; -webkit-font-smoothing: antialiased; -moz-osx-font-smoothing: grayscale; }
        html { scroll-behavior: smooth; }
        [id] { scroll-margin-top: 80px; }
        ::selection { background: rgba(212,162,74,0.4); color: #222222; }
        @keyframes breathe { 0%,100% { opacity: 0.25; } 50% { opacity: 0.85; } }
        ::-webkit-scrollbar { width: 4px; }
        ::-webkit-scrollbar-track { background: #ffffff; }
        ::-webkit-scrollbar-thumb { background: rgba(212,162,74,0.3); border-radius: 2px; }
        ::-webkit-scrollbar-thumb:hover { background: rgba(212,162,74,0.45); }
      `}</style>
      <Nav scrolled={scrolled} />
      <Hero />
      <About />
      <DualImage />
      <Experience />
      <FullWidthImage />
      <GallerySection />
      <Features />
      <Pricing />
      <Contact />
      <Footer />
    </>
  );
}
